import{_ as t,o as n,c as i,ai as a}from"./chunks/framework.LYGRWSbL.js";const h=JSON.parse('{"title":"La négation","description":"","frontmatter":{"next":{"text":"Module 3 - Le quotidien","link":"../module-3-quotidien/"}},"headers":[],"relativePath":"module-2-construire-une-phrase/negation.md","filePath":"module-2-construire-une-phrase/negation.md","lastUpdated":1773233444000}'),r={name:"module-2-construire-une-phrase/negation.md"};function s(l,e,o,d,c,m){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="la-negation" tabindex="-1">La négation <a class="header-anchor" href="#la-negation" aria-label="Permalink to “La négation”">​</a></h1><p><strong>Prérequis :</strong> <a href="./pronoms-personnels.html">Les pronoms personnels</a></p><p><strong>Objectif :</strong> savoir former une phrase negative avec nicht et kein, et comprendre quand utiliser l&#39;un ou l&#39;autre.</p><p>La negation en allemand utilise deux mots differents selon ce qu&#39;on nie. C&#39;est une des premieres difficultes pour les francophones habitues a un seul &quot;ne... pas&quot;.</p><h2 id="la-regle-de-base" tabindex="-1">La regle de base <a class="header-anchor" href="#la-regle-de-base" aria-label="Permalink to “La regle de base”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-red-200 bg-red-50"><div class="font-bold text-red-800 text-lg">nicht</div><div class="text-sm text-red-700 mt-1">Nie une action, un adjectif, un adverbe, ou un nom avec article defini</div><div class="text-sm text-gray-600 mt-2">= &quot;ne... pas&quot;</div></div><div class="p-4 rounded-xl border border-orange-200 bg-orange-50"><div class="font-bold text-orange-800 text-lg">kein / keine / kein</div><div class="text-sm text-orange-700 mt-1">Nie un nom avec article indefini (ein) ou sans article</div><div class="text-sm text-gray-600 mt-2">= &quot;pas de&quot; / &quot;aucun&quot;</div></div></div><h2 id="nicht-la-negation-de-l-action-ou-de-l-adjectif" tabindex="-1">nicht - la negation de l&#39;action ou de l&#39;adjectif <a class="header-anchor" href="#nicht-la-negation-de-l-action-ou-de-l-adjectif" aria-label="Permalink to “nicht - la negation de l&#39;action ou de l&#39;adjectif”">​</a></h2><h3 id="nier-le-verbe" tabindex="-1">Nier le verbe <a class="header-anchor" href="#nier-le-verbe" aria-label="Permalink to “Nier le verbe”">​</a></h3><p><em>Nicht</em> se place <strong>en fin de phrase</strong> quand il nie l&#39;ensemble de l&#39;action :</p><ul><li><em>Ich arbeite.</em> → <em>Ich arbeite <strong>nicht</strong>.</em> - Je ne travaille pas.</li><li><em>Er kommt.</em> → <em>Er kommt <strong>nicht</strong>.</em> - Il ne vient pas.</li><li><em>Sie schläft.</em> → <em>Sie schläft <strong>nicht</strong>.</em> - Elle ne dort pas.</li></ul><h3 id="nier-un-adjectif-ou-un-adverbe" tabindex="-1">Nier un adjectif ou un adverbe <a class="header-anchor" href="#nier-un-adjectif-ou-un-adverbe" aria-label="Permalink to “Nier un adjectif ou un adverbe”">​</a></h3><p><em>Nicht</em> se place <strong>avant</strong> l&#39;element nie :</p><ul><li><em>Das ist gut.</em> → <em>Das ist <strong>nicht</strong> gut.</em> - Ce n&#39;est pas bon.</li><li><em>Er kommt oft.</em> → <em>Er kommt <strong>nicht</strong> oft.</em> - Il ne vient pas souvent.</li></ul><h3 id="nier-un-nom-avec-article-defini" tabindex="-1">Nier un nom avec article defini <a class="header-anchor" href="#nier-un-nom-avec-article-defini" aria-label="Permalink to “Nier un nom avec article defini”">​</a></h3><p><em>Nicht</em> se place avant l&#39;article :</p><ul><li><em>Ich lese die Zeitung.</em> → <em>Ich lese <strong>nicht</strong> die Zeitung.</em> - Je ne lis pas le journal.</li></ul><h2 id="kein-la-negation-du-nom-indefini" tabindex="-1">kein - la negation du nom indefini <a class="header-anchor" href="#kein-la-negation-du-nom-indefini" aria-label="Permalink to “kein - la negation du nom indefini”">​</a></h2><p><em>Kein</em> remplace l&#39;article indefini <em>ein/eine</em> et se decline comme lui :</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600"></th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Feminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">ein →</td><td class="p-3 text-center font-bold text-blue-700">kein</td><td class="p-3 text-center font-bold text-red-600">keine</td><td class="p-3 text-center font-bold text-green-700">kein</td><td class="p-3 text-center font-bold text-gray-700">keine</td></tr></tbody></table></div><p>Exemples :</p><ul><li><em>Ich habe ein Auto.</em> → <em>Ich habe <strong>kein</strong> Auto.</em> - Je n&#39;ai pas de voiture.</li><li><em>Er hat eine Schwester.</em> → <em>Er hat <strong>keine</strong> Schwester.</em> - Il n&#39;a pas de soeur.</li><li><em>Ich trinke Kaffee.</em> → <em>Ich trinke <strong>keinen</strong> Kaffee.</em> - Je ne bois pas de cafe.</li></ul><div class="warning custom-block"><p class="custom-block-title">La declinaison de kein change selon le cas</p><p>Au nominatif, <em>kein</em> = masculin, <em>keine</em> = feminin, <em>kein</em> = neutre. Mais a l&#39;accusatif (lecon suivante), le masculin devient <em>keinen</em>. Apprends les exemples par coeur pour l&#39;instant - les cas seront detailles dans le module 3.</p></div><h2 id="aide-memoire-nicht-ou-kein" tabindex="-1">Aide-memoire : nicht ou kein ? <a class="header-anchor" href="#aide-memoire-nicht-ou-kein" aria-label="Permalink to “Aide-memoire : nicht ou kein ?”">​</a></h2><div class="mt-4 p-5 rounded-xl border border-green-200 bg-green-50"><div class="font-semibold text-green-800 mb-3">Question a se poser : est-ce qu&#39;il y a un article *ein* (ou pas d&#39;article) devant le nom ?</div><div class="grid gap-2"><div class="flex items-start gap-2"><span class="font-bold text-green-700 mt-0.5">Oui</span><span class="text-gray-700">→ utilise <strong>kein/keine</strong> : <em>Ich habe keine Zeit.</em> (Je n&#39;ai pas le temps.)</span></div><div class="flex items-start gap-2"><span class="font-bold text-red-600 mt-0.5">Non</span><span class="text-gray-700">→ utilise <strong>nicht</strong> : <em>Ich arbeite nicht.</em> (Je ne travaille pas.)</span></div></div></div><div class="tip custom-block"><p class="custom-block-title">doch - si (pour contredire un non)</p><p>Si quelqu&#39;un dit quelque chose de negatif et que tu veux contredire, utilise <em>doch</em> plutot que <em>ja</em> :</p><ul><li><em>Du arbeitest nicht.</em> - Tu ne travailles pas.</li><li><em><strong>Doch</strong>, ich arbeite !</em> - Si, je travaille ! C&#39;est un mot tres courant en allemand qui n&#39;a pas d&#39;equivalent direct en français.</li></ul></div>',25)])])}const p=t(r,[["render",s]]);export{h as __pageData,p as default};
